-- Close remaining RLS gaps and remove duplicated permissive policies.
-- No business data is modified.

drop policy if exists automation_rules_select_scoped on public.automation_rules;
create policy automation_rules_select_scoped on public.automation_rules for select to authenticated using (organization_id = (select public.current_org_id()) and (select public.current_app_role()) = any (array['admin','direction','operations']::public.app_role[]));
