create policy automation_rules_update_scoped on public.automation_rules for update to authenticated using (organization_id = (select public.current_org_id()) and (select public.current_app_role()) = any (array['admin','direction']::public.app_role[])) with check (organization_id = (select public.current_org_id()) and (select public.current_app_role()) = any (array['admin','direction']::public.app_role[]));
